<?php include('includes/sidebar.php');?><main class="app-main"><?php include('includes/nav.php');?><div class="content-wrap">
<div class="page-card mb-3"><div class="page-head"><div><div class="page-title">New Pawn Entry</div><div class="small text-muted">Create a pawn loan using current categories, metals and customers.</div></div><a href="pawn-list.php" class="btn-soft">Pawn List</a></div></div>
