<div class="page-card mb-3"><div class="page-head"><div class="section-title">Pawn Items</div><button type="button" class="btn-theme" id="addItemBtn">Add Item</button></div><div class="card-body-x" id="itemsWrap"></div></div>
</div><div class="col-xl-3"><div class="page-card"><div class="page-head"><div class="section-title">Loan Details</div></div><div class="card-body-x"><div class="mb-2"><label class="small fw-bold">Principal Amount</label><input type="number" step="0.01" min="0.01" name="principal_amount" class="form-control" required></div><div class="mb-2"><label class="small fw-bold">Interest %</label><input type="number" step="0.001" min="0" name="interest_percent" id="interestPercent" class="form-control" required></div><div class="mb-2"><label class="small fw-bold">Interest Period</label><select name="interest_period" class="form-select"><option>Monthly</option><option>Daily</option><option>Yearly</option></select></div><div class="mb-2"><label class="small fw-bold">Remarks</label><textarea name="remarks" class="form-control" rows="3"></textarea></div><hr><div class="d-flex justify-content-between small"><span>Total Gross</span><strong id="totalGross">0.000 g</strong></div><div class="d-flex justify-content-between small mt-2"><span>Total Net</span><strong id="totalNet">0.000 g</strong></div><div class="d-flex justify-content-between small mt-2"><span>Estimated Value</span><strong>₹<span id="totalEstimated">0.00</span></strong></div><button type="submit" class="btn-theme w-100 mt-3" id="saveBtn">Save Pawn Entry</button></div></div></div></div></form>
